64	async function getFixtureIds(
65		request: import('@playwright/test').APIRequestContext
66	): Promise<{
67		nodeId: string;
68		projectId: string;
69		nodeName: string;
70		projectName: string;
71		projectPath: string;
72	}> {
73		const nodeResp = await request.post('/graphql', {
74			data: { query: '{ nodeInfo { id name } }' }
75		});
76		const nodeBody = (await nodeResp.json()) as { data: { nodeInfo: { id: string; name: string } } };
77		const projectsResp = await request.get('/api/projects');
78		const projects = (await projectsResp.json()) as Array<{ id: string; name: string; path: string }>;
79		const fixture = projects.find((p) => /(^|\/)ddx-e2e-/.test(p.path) || /^ddx-e2e-/.test(p.name));
80		if (!fixture) {
81			throw new Error(
82				`fixture server has no ddx-e2e-* project registered (got: ${projects.map((p) => p.id).join(', ')})`
83			);
84		}
85		return {
86			nodeId: nodeBody.data.nodeInfo.id,
87			projectId: fixture.id,
88			nodeName: nodeBody.data.nodeInfo.name,
89			projectName: fixture.name,
90			projectPath: fixture.path
91		};
92	}
